-- ============================================
-- Zuu Crew AI (Pvt) Ltd - IT Operations Database
-- Generated for AEE Bootcamp Final Hackathon
-- ============================================

DROP TABLE IF EXISTS incident_history CASCADE;
DROP TABLE IF EXISTS live_tickets CASCADE;
DROP TABLE IF EXISTS assets_inventory CASCADE;
DROP TABLE IF EXISTS services CASCADE;
DROP TABLE IF EXISTS employees CASCADE;
DROP TABLE IF EXISTS divisions CASCADE;

-- ============================================
-- Table: divisions
-- ============================================
CREATE TABLE divisions (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT
);


-- ============================================
-- Table: employees (750 rows)
-- ============================================
CREATE TABLE employees (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    email TEXT UNIQUE NOT NULL,
    role TEXT NOT NULL,
    division_id TEXT REFERENCES divisions(id),
    clearance_level INT CHECK (clearance_level BETWEEN 1 AND 5),
    shift TEXT CHECK (shift IN ('day', 'night', 'flexible')),
    manager_id TEXT,
    joined_date DATE,
    is_active BOOLEAN DEFAULT TRUE
);


-- ============================================
-- Table: services (25 rows)
-- ============================================
CREATE TABLE services (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT,
    owner_division TEXT REFERENCES divisions(id),
    status TEXT CHECK (status IN ('healthy', 'degraded', 'offline', 'maintenance')),
    last_deploy TIMESTAMP,
    version TEXT
);


-- ============================================
-- Table: assets_inventory (200 rows)
-- ============================================
CREATE TABLE assets_inventory (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    asset_type TEXT CHECK (asset_type IN ('server', 'laptop', 'network_switch', 'load_balancer', 'storage_array')),
    status TEXT CHECK (status IN ('healthy', 'degraded', 'offline', 'maintenance')),
    owner_id TEXT REFERENCES employees(id),
    cpu_usage_percent INT,
    memory_usage_percent INT,
    location TEXT,
    last_health_check TIMESTAMP
);


-- ============================================
-- Table: live_tickets (150 rows)
-- ============================================
CREATE TABLE live_tickets (
    id TEXT PRIMARY KEY,
    reported_by TEXT REFERENCES employees(id),
    issue_description TEXT NOT NULL,
    ticket_type TEXT CHECK (ticket_type IN ('access_identity', 'asset_provisioning', 'service_degradation', 'critical_outage')),
    severity TEXT CHECK (severity IN ('low', 'medium', 'high', 'critical')),
    status TEXT CHECK (status IN ('open', 'investigating', 'resolved', 'closed')),
    assigned_to TEXT REFERENCES employees(id),
    created_at TIMESTAMP,
    resolved_at TIMESTAMP,
    resolution_notes TEXT
);


-- ============================================
-- Table: incident_history (300 rows)
-- ============================================
CREATE TABLE incident_history (
    id TEXT PRIMARY KEY,
    title TEXT NOT NULL,
    ticket_type TEXT CHECK (ticket_type IN ('access_identity', 'asset_provisioning', 'service_degradation', 'critical_outage')),
    severity TEXT CHECK (severity IN ('low', 'medium', 'high', 'critical')),
    resolved_by TEXT REFERENCES employees(id),
    resolution_notes TEXT,
    resolution_time_minutes INT,
    occurred_at TIMESTAMP,
    resolved_at TIMESTAMP,
    affected_service TEXT,
    root_cause TEXT CHECK (root_cause IN ('configuration_drift', 'resource_exhaustion', 'software_bug', 'human_error', 'external_attack', 'hardware_failure'))
);


-- ============================================
-- Indexes
-- ============================================
CREATE INDEX idx_employees_division ON employees(division_id);
CREATE INDEX idx_employees_clearance ON employees(clearance_level);
CREATE INDEX idx_assets_status ON assets_inventory(status);
CREATE INDEX idx_assets_owner ON assets_inventory(owner_id);
CREATE INDEX idx_tickets_type ON live_tickets(ticket_type);
CREATE INDEX idx_tickets_status ON live_tickets(status);
CREATE INDEX idx_tickets_reporter ON live_tickets(reported_by);
CREATE INDEX idx_incidents_type ON incident_history(ticket_type);
CREATE INDEX idx_incidents_service ON incident_history(affected_service);

-- End of zuucrew_ops.sql